// AuthContext.js
import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import oidcService from './oidc-service';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  // Initialize auth state on mount
  useEffect(() => {
    const initAuth = () => {
      try {
        if (oidcService.isAuthenticated()) {
          const profile = oidcService.getUserProfile();
          if (profile) {
            setUser(profile);
            setIsAuthenticated(true);
          }
        }
      } catch (err) {
        console.error('Auth initialization error:', err);
      } finally {
        setIsLoading(false);
      }
    };

    initAuth();
  }, []);

  // Set up token refresh interval
  useEffect(() => {
    if (!isAuthenticated) return;

    const tokens = oidcService.getTokens();
    if (!tokens || !tokens.expires_at || !tokens.refresh_token) return;

    // Refresh 60 seconds before expiration
    const refreshTime = tokens.expires_at - Date.now() - 60000;

    if (refreshTime <= 0) {
      // Token already expired or about to expire, refresh now
      oidcService
        .refreshTokens()
        .then(() => {
          const profile = oidcService.getUserProfile();
          setUser(profile);
        })
        .catch(() => {
          setUser(null);
          setIsAuthenticated(false);
        });
      return;
    }

    const timer = setTimeout(async () => {
      try {
        await oidcService.refreshTokens();
        const profile = oidcService.getUserProfile();
        setUser(profile);
      } catch {
        setUser(null);
        setIsAuthenticated(false);
      }
    }, refreshTime);

    return () => clearTimeout(timer);
  }, [isAuthenticated]);

  const login = useCallback(async () => {
    setError(null);
    try {
      await oidcService.login();
    } catch (err) {
      setError(err.message);
    }
  }, []);

  const handleCallback = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await oidcService.handleCallback();
      setUser(result.userProfile);
      setIsAuthenticated(true);
      return result.redirectTo;
    } catch (err) {
      setError(err.message);
      setIsAuthenticated(false);
      setUser(null);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const logout = useCallback(async () => {
    try {
      await oidcService.logout();
    } catch {
      oidcService.clearTokens();
      setUser(null);
      setIsAuthenticated(false);
    }
  }, []);

  const getAccessToken = useCallback(() => {
    return oidcService.getAccessToken();
  }, []);

  const value = {
    user,
    isAuthenticated,
    isLoading,
    error,
    login,
    logout,
    handleCallback,
    getAccessToken,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

export default AuthContext;

